def get_matrix_and_jobs(current_sequence: list, time_matrix: np.ndarray,
                         m: int, n: int) -> tuple:
    import numpy as np

    new_matrix = time_matrix.copy()

    # Compute completion times
    C = np.zeros((n, m))
    for i, job in enumerate(current_sequence):
        for j in range(m):
            if i == 0 and j == 0:
                C[i, j] = time_matrix[job, j]
            elif i == 0:
                C[i, j] = C[i, j-1] + time_matrix[job, j]
            elif j == 0:
                C[i, j] = C[i-1, j] + time_matrix[job, j]
            else:
                C[i, j] = max(C[i-1, j], C[i, j-1]) + time_matrix[job, j]

    # Compute idle time each job causes on each machine
    idle_impact = np.zeros(n)
    for i, job in enumerate(current_sequence):
        for j in range(1, m):
            if i == 0:
                idle = C[i, j-1] - C[i, j] + time_matrix[job, j]
            else:
                idle = max(0, C[i-1, j] - C[i, j-1])
            idle_impact[job] += idle

    # Determine threshold: mean idle impact
    threshold = np.mean(idle_impact) if n > 0 else 0
    bottleneck_jobs = np.where(idle_impact > threshold)[0]

    # Apply deterministic penalty (multiply by 1.3) to bottleneck jobs on all machines
    for job in bottleneck_jobs:
        new_matrix[job, :] *= 1.3

    # Select jobs to perturb: bottleneck jobs sorted by idle impact (descending)
    if len(bottleneck_jobs) > 0:
        sorted_bottleneck = bottleneck_jobs[np.argsort(-idle_impact[bottleneck_jobs])]
        perturb_jobs = sorted_bottleneck[:5].tolist()
        if len(perturb_jobs) < 2:
            for i in range(n):
                if len(perturb_jobs) >= 2:
                    break
                if i not in perturb_jobs:
                    perturb_jobs.append(i)
    else:
        perturb_jobs = list(range(min(5, n)))

    perturb_jobs = perturb_jobs[:5]
    if len(perturb_jobs) < 2:
        for i in range(n):
            if len(perturb_jobs) >= 2:
                break
            if i not in perturb_jobs:
                perturb_jobs.append(i)

    return new_matrix, perturb_jobs

def get_matrix_and_jobs(current_sequence: list, time_matrix: np.ndarray,
                         m: int, n: int) -> tuple:
    new_matrix = time_matrix.copy()

    # Compute start, completion, and slack times
    start = np.zeros((n, m))
    comp = np.zeros((n, m))
    for j in range(m):
        for i in range(n):
            job = current_sequence[i]
            if i == 0 and j == 0:
                start[i][j] = 0
            elif i == 0:
                start[i][j] = comp[i][j-1]
            elif j == 0:
                start[i][j] = comp[i-1][j]
            else:
                start[i][j] = max(comp[i-1][j], comp[i][j-1])
            comp[i][j] = start[i][j] + time_matrix[job][j]

    makespan = comp[-1][-1]

    # Compute latest start times (backward pass)
    latest_start = np.zeros((n, m))
    latest_comp = np.full((n, m), makespan)
    for j in range(m-1, -1, -1):
        for i in range(n-1, -1, -1):
            job = current_sequence[i]
            if i == n-1 and j == m-1:
                latest_comp[i][j] = makespan
            elif i == n-1:
                latest_comp[i][j] = latest_start[i][j+1]
            elif j == m-1:
                latest_comp[i][j] = latest_start[i+1][j]
            else:
                latest_comp[i][j] = min(latest_start[i+1][j], latest_start[i][j+1])
            latest_start[i][j] = latest_comp[i][j] - time_matrix[job][j]

    # Compute slack per job per machine on critical path
    # First identify critical path jobs and machines
    critical_jobs = []
    critical_machines = []
    i, j = n-1, m-1
    while i >= 0 and j >= 0:
        job = current_sequence[i]
        critical_jobs.append(job)
        critical_machines.append(j)
        if i == 0 and j == 0:
            break
        if i == 0:
            j -= 1
        elif j == 0:
            i -= 1
        else:
            if comp[i-1][j] >= comp[i][j-1]:
                i -= 1
            else:
                j -= 1
    critical_jobs.reverse()
    critical_machines.reverse()

    # Compute total slack per job (sum of slack on critical path machines)
    job_slack = {job: 0 for job in range(n)}
    for job, mach in zip(critical_jobs, critical_machines):
        idx = current_sequence.index(job) if job in current_sequence else -1
        if idx != -1:
            job_slack[job] += (latest_start[idx][mach] - start[idx][mach])

    # Select bottleneck jobs by highest slack (most flexible -> potential improvement)
    sorted_jobs = sorted(range(n), key=lambda j: job_slack[j], reverse=True)
    bottleneck_jobs = sorted_jobs[:max(2, min(5, n))]

    # For each bottleneck job, reduce processing time on its critical machine with highest slack
    for job in bottleneck_jobs:
        # Find the machine where this job appears on critical path with max slack
        candidate_machines = []
        for idx, (j, mach) in enumerate(zip(critical_jobs, critical_machines)):
            if j == job:
                candidate_machines.append(mach)
        if candidate_machines:
            # Choose machine with largest local slack contribution
            # (approximate by using latest_start - start for that operation)
            best_machine = candidate_machines[0]
            best_slack = -1
            for mach in candidate_machines:
                pos = current_sequence.index(job)
                slack_val = latest_start[pos][mach] - start[pos][mach]
                if slack_val > best_slack:
                    best_slack = slack_val
                    best_machine = mach
            new_matrix[job][best_machine] *= 0.8  # Reduce to encourage exploration

    perturb_jobs = bottleneck_jobs[:max(2, min(5, n))]

    return new_matrix, perturb_jobs
